108	static struct qemu_plugin_register *find_reg(GArray *regs, const char *name)
109	{
110	    for (guint i = 0; i < regs->len; i++) {
111	        qemu_plugin_reg_descriptor *rd =
112	            &g_array_index(regs, qemu_plugin_reg_descriptor, i);
113	        if (g_ascii_strcasecmp(rd->name, name) == 0) {
114	            return rd->handle;
115	        }
116	    }
117	    return NULL;
118	}
