120	// Lazily resolves register handles. The plugin's vcpu_init runs before
121	// QEMU has registered the dynamic gdb coprocessors (FPU, virtual, csr,
122	// vector), so qemu_plugin_get_registers() returns only the 33 core CPU
123	// regs at that moment. By the time the entry trigger fires, all dynamic
124	// features are registered and a fresh call returns the full list.
125	static void resolve_handles(VcpuRegs *v)
126	{
127	    g_autoptr(GArray) regs = qemu_plugin_get_registers();
128	    for (int i = 0; i < 32; i++) {
129	        v->gpr[i] = find_reg(regs, hybrid_gpr_names[i]);
130	        v->fpr[i] = find_reg(regs, hybrid_fpr_names[i]);
131	    }
132	    v->pc = find_reg(regs, "pc");
133	
134	    v->mstatus  = find_reg(regs, "mstatus");
135	    v->mepc     = find_reg(regs, "mepc");
136	    v->mtvec    = find_reg(regs, "mtvec");
137	    v->mcause   = find_reg(regs, "mcause");
138	    v->mtval    = find_reg(regs, "mtval");
139	    v->mscratch = find_reg(regs, "mscratch");
140	    v->medeleg  = find_reg(regs, "medeleg");
141	    v->mideleg  = find_reg(regs, "mideleg");
142	    v->mip      = find_reg(regs, "mip");
143	    v->mie      = find_reg(regs, "mie");
144	    v->mcycle   = find_reg(regs, "mcycle");
145	    v->minstret = find_reg(regs, "minstret");
146	    v->satp     = find_reg(regs, "satp");
147	
148	    char buf[16];
149	    for (int i = 0; i < HYBRID_PMP_CFG_NUM; i++) {
150	        g_snprintf(buf, sizeof(buf), "pmpcfg%d", i);
151	        v->pmpcfg[i] = find_reg(regs, buf);
152	    }
153	    for (int i = 0; i < HYBRID_PMP_ADDR_NUM; i++) {
154	        g_snprintf(buf, sizeof(buf), "pmpaddr%d", i);
155	        v->pmpaddr[i] = find_reg(regs, buf);
156	    }
157	
158	    v->vstart = find_reg(regs, "vstart");
159	    v->vxsat  = find_reg(regs, "vxsat");
160	    v->vxrm   = find_reg(regs, "vxrm");
161	    v->vcsr   = find_reg(regs, "vcsr");
162	    v->vtype  = find_reg(regs, "vtype");
163	    v->vl     = find_reg(regs, "vl");
164	    v->vlenb  = find_reg(regs, "vlenb");
165	    for (int i = 0; i < 32; i++) {
166	        g_snprintf(buf, sizeof(buf), "v%d", i);
167	        v->vreg[i] = find_reg(regs, buf);
168	    }
169	}
