197	// Atomic on POSIX: write to .tmp, fsync, rename.
198	static int write_state_atomic(const struct hybrid_state_v1 *s, const char *path)
199	{
200	    char tmp[PATH_MAX];
201	    g_snprintf(tmp, sizeof(tmp), "%s.tmp.%d", path, (int) getpid());
202	    int fd = open(tmp, O_WRONLY | O_CREAT | O_TRUNC, 0600);
203	    if (fd < 0) {
204	        perror("hybrid_handoff: open tmp");
205	        return -1;
206	    }
207	    ssize_t want = (ssize_t) sizeof(*s);
208	    ssize_t got = write(fd, s, sizeof(*s));
209	    if (got != want) {
210	        perror("hybrid_handoff: write");
211	        close(fd);
212	        unlink(tmp);
213	        return -1;
214	    }
215	    fsync(fd);
216	    close(fd);
217	    if (rename(tmp, path) != 0) {
218	        perror("hybrid_handoff: rename");
219	        unlink(tmp);
220	        return -1;
221	    }
222	    return 0;
223	}
