225	static void on_handoff(unsigned int vcpu_idx, void *udata)
226	{
227	    const HandoffSite *site = (const HandoffSite *) udata;
228	    if (site->kind != HYBRID_HANDOFF_ENTER) return;
229	
230	    VcpuRegs *v = qemu_plugin_scoreboard_find(vcpu_state, vcpu_idx);
231	    resolve_handles(v);
232	    struct hybrid_state_v1 s = {0};
233	    s.magic   = HYBRID_STATE_MAGIC;
234	    s.version = HYBRID_STATE_VERSION;
235	    s.flags   = HYBRID_FLAG_RV64;
236	    s.hart_id = vcpu_idx;
237	    s.priv    = 3;
238	    // PC via translation-time vaddr+size; reading the gdbstub PC inside the
239	    // exec callback can lag the actual current insn when V instructions
240	    // retire just before the trigger (TCG defers PC writes for performance).
241	    s.pc      = compute_handoff_pc(site);
242	    for (int i = 0; i < 32; i++) s.gpr[i] = read_reg64(v->gpr[i]);
243	
244	    // Floating-point: only set FP flag if at least one handle was bound,
245	    // i.e. QEMU advertised the FPU feature (D extension).
246	    int has_fp = 0;
247	    for (int i = 0; i < 32; i++) {
248	        s.fpr[i] = read_reg64(v->fpr[i]);
249	        if (v->fpr[i]) has_fp = 1;
250	    }
251	    if (has_fp) s.flags |= HYBRID_FLAG_FP;
252	
253	    s.mstatus  = read_reg64(v->mstatus);
254	    s.mepc     = read_reg64(v->mepc);
255	    s.mtvec    = read_reg64(v->mtvec);
256	    s.mcause   = read_reg64(v->mcause);
257	    s.mtval    = read_reg64(v->mtval);
258	    s.mscratch = read_reg64(v->mscratch);
259	    s.medeleg  = read_reg64(v->medeleg);
260	    s.mideleg  = read_reg64(v->mideleg);
261	    s.mip      = read_reg64(v->mip);
262	    s.mie      = read_reg64(v->mie);
263	    s.mcycle   = read_reg64(v->mcycle);
264	    s.minstret = read_reg64(v->minstret);
265	    s.satp     = read_reg64(v->satp);
266	
267	    for (int i = 0; i < HYBRID_PMP_CFG_NUM; i++)
268	        s.pmpcfg[i] = read_reg64(v->pmpcfg[i]);
269	    for (int i = 0; i < HYBRID_PMP_ADDR_NUM; i++)
270	        s.pmpaddr[i] = read_reg64(v->pmpaddr[i]);
271	
272	    // Vector: only set V flag if QEMU advertised the V extension. vlenb
273	    // bounds the per-register byte count copied into vreg[].
274	    s.vstart = read_reg64(v->vstart);
275	    s.vxsat  = read_reg64(v->vxsat);
276	    s.vxrm   = read_reg64(v->vxrm);
277	    s.vcsr   = read_reg64(v->vcsr);
278	    s.vtype  = read_reg64(v->vtype);
279	    s.vl     = read_reg64(v->vl);
280	    s.vlenb  = read_reg64(v->vlenb);
281	    if (v->vlenb && s.vlenb > 0) {
282	        s.flags |= HYBRID_FLAG_V;
283	        size_t bytes = s.vlenb < HYBRID_VLEN_BYTES_MAX
284	                     ? (size_t) s.vlenb
285	                     : (size_t) HYBRID_VLEN_BYTES_MAX;
286	        for (int i = 0; i < 32; i++)
287	            (void) read_reg_bytes(v->vreg[i],
288	                                  &s.vreg[(size_t) i * HYBRID_VLEN_BYTES_MAX],
289	                                  bytes);
290	    }
291	
292	    if (write_state_atomic(&s, outfile_path) != 0) {
293	        fprintf(stderr, "hybrid_handoff: failed to write state file\n");
294	        exit(2);
295	    }
296	    fprintf(stderr,
297	            "hybrid_handoff: drained state to %s (pc=%#" PRIx64 "), exiting\n",
298	            outfile_path, s.pc);
299	    // 200 == kExitHandoffToQemu in verilator/src/hybrid/exit_codes.hpp.
300	    // Distinguishes drain from workload completion (0) so the orchestrator
301	    // can decide the next spawn.
302	    exit(200);
303	}
304	
305	// Per-insn tick for icount mode. udata is the per-insn HandoffSite
306	// pre-allocated at translation time, so on_handoff's compute_handoff_pc
307	// returns the lag-free post-trigger PC (same property as the CSR path).
308	static void on_icount_tick(unsigned int vcpu_idx, void *udata)
309	{
310	    VcpuRegs *v = qemu_plugin_scoreboard_find(vcpu_state, vcpu_idx);
311	    if (++v->icount_retired < icount_target) return;
312	    on_handoff(vcpu_idx, udata);
313	}
314	
315	// Per-insn tick for BBV-emit mode. udata is the bb_id (1-based) cast to
316	// pointer; that mapping is stable across calls because bbv_emit_assign_id
317	// is hashed by TB-start PC. The tick attributes one insn to the bb_id and
318	// flushes a slice row when the per-slice counter saturates.
319	static void on_bbv_tick(unsigned int vcpu_idx, void *udata)
320	{
321	    (void) vcpu_idx;
322	    uint64_t bb_id = (uint64_t) GPOINTER_TO_UINT(udata);
323	    bbv_emit_tick(bbv_emit, bb_id);
324	}
325	
326	// Per-insn tick for slice-consume mode (F11). Counts insns into the
327	// slice accumulator; on each slice boundary increments slice_consume_idx
328	// and resets the accumulator. Once slice_consume_idx exceeds the target
329	// slice index, drains via on_handoff at that same insn boundary. udata
330	// is the per-insn HandoffSite (allocated at translation time) so the
331	// post-trigger PC reaches on_handoff lag-free.
332	static void on_slice_consume_tick(unsigned int vcpu_idx, void *udata)
333	{
334	    if (++slice_consume_acc < bbv_slice_target) return;
335	    slice_consume_acc = 0;
336	    if (slice_consume_idx++ < slice_at_target) return;
337	    // After the post-increment above, slice_consume_idx == slice_at_target+1
338	    // (the count of fully retired slices). Log so the e2e test can verify
339	    // drain timing without relying on minstret (which is a cycle-counter
340	    // proxy on andes-ax45mpv and does not track plugin-counted insns).
341	    fprintf(stderr,
342	            "hybrid_handoff: slice-consume drain (idx=%" PRIu64
343	            " target=%" PRIu64 ")\n",
344	            slice_consume_idx, slice_at_target);
345	    on_handoff(vcpu_idx, udata);
346	}
