348	static void vcpu_tb_trans(qemu_plugin_id_t id, struct qemu_plugin_tb *tb)
349	{
350	    (void) id;
351	    size_t n = qemu_plugin_tb_n_insns(tb);
352	
353	    // BBV-mode: assign a stable bb_id to this TB (1-based, hashed by
354	    // TB-start vaddr). Same id is shared by every insn in the TB.
355	    uint64_t bb_id = 0;
356	    if (bbv_mode && n > 0) {
357	        uint64_t tb_pc = qemu_plugin_insn_vaddr(qemu_plugin_tb_get_insn(tb, 0));
358	        bb_id = bbv_emit_assign_id(bbv_emit, tb_pc);
359	    }
360	
361	    for (size_t i = 0; i < n; i++) {
362	        struct qemu_plugin_insn *insn = qemu_plugin_tb_get_insn(tb, i);
363	
364	        // BBV callback is registered BEFORE icount so that if both modes
365	        // fire on the same insn (icount target == slice multiple), the
366	        // slice row is emitted before exit(200) is called.
367	        if (bbv_mode) {
368	            qemu_plugin_register_vcpu_insn_exec_cb(
369	                insn, on_bbv_tick, QEMU_PLUGIN_CB_NO_REGS,
370	                GUINT_TO_POINTER((guint) bb_id));
371	        }
372	
373	        // Slice-consume callback (F11). Registered after BBV so a BBV
374	        // row at the same boundary is flushed first; ordering vs icount
375	        // is irrelevant (both drain).
376	        if (slice_consume_mode) {
377	            HandoffSite *site = g_new0(HandoffSite, 1);
378	            site->kind  = HYBRID_HANDOFF_ENTER;
379	            site->vaddr = qemu_plugin_insn_vaddr(insn);
380	            site->size  = (uint32_t) qemu_plugin_insn_size(insn);
381	            qemu_plugin_register_vcpu_insn_exec_cb(
382	                insn, on_slice_consume_tick, QEMU_PLUGIN_CB_R_REGS, site);
383	        }
384	
385	        if (icount_mode) {
386	            HandoffSite *site = g_new0(HandoffSite, 1);
387	            site->kind  = HYBRID_HANDOFF_ENTER;
388	            site->vaddr = qemu_plugin_insn_vaddr(insn);
389	            site->size  = (uint32_t) qemu_plugin_insn_size(insn);
390	            qemu_plugin_register_vcpu_insn_exec_cb(
391	                insn, on_icount_tick, QEMU_PLUGIN_CB_R_REGS, site);
392	        }
393	
394	        if (pc_mode) {
395	            // PC-trigger mode: vaddr-only match. qemu_plugin_insn_size lets
396	            // a future fixture park enter_pc on a compressed insn -- next-PC
397	            // is computed from the API-reported size, not assumed to be 4.
398	            if (qemu_plugin_insn_vaddr(insn) != enter_pc_arg) continue;
399	            HandoffSite *site = g_new0(HandoffSite, 1);
400	            site->kind  = HYBRID_HANDOFF_ENTER;
401	            site->vaddr = qemu_plugin_insn_vaddr(insn);
402	            site->size  = (uint32_t) qemu_plugin_insn_size(insn);
403	            qemu_plugin_register_vcpu_insn_exec_cb(
404	                insn, on_handoff, QEMU_PLUGIN_CB_R_REGS, site);
405	            continue;
406	        }
407	
408	        // CSR-trigger mode (default).
409	        size_t sz = qemu_plugin_insn_size(insn);
410	        if (sz != 4) continue;
411	        uint32_t raw = 0;
412	        if (qemu_plugin_insn_data(insn, &raw, sizeof(raw)) != sizeof(raw))
413	            continue;
414	        hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
415	        if (!hybrid_match_handoff_insn(raw, &kind)) continue;
416	        HandoffSite *site = g_new0(HandoffSite, 1);
417	        site->kind  = kind;
418	        site->vaddr = qemu_plugin_insn_vaddr(insn);
419	        site->size  = (uint32_t) sz;
420	        qemu_plugin_register_vcpu_insn_exec_cb(
421	            insn, on_handoff, QEMU_PLUGIN_CB_R_REGS, site);
422	    }
423	}
