425	QEMU_PLUGIN_EXPORT int qemu_plugin_install(qemu_plugin_id_t id,
426	                                           const qemu_info_t *info,
427	                                           int argc, char **argv)
428	{
429	    (void) info;
430	    for (int i = 0; i < argc; i++) {
431	        g_auto(GStrv) tok = g_strsplit(argv[i], "=", 2);
432	        if (g_strcmp0(tok[0], "outfile") == 0 && tok[1]) {
433	            outfile_path = g_strdup(tok[1]);
434	        } else if (g_strcmp0(tok[0], "enter_pc") == 0 && tok[1]) {
435	            char *endp = NULL;
436	            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
437	            if (!endp || *endp != '\0') {
438	                fprintf(stderr, "hybrid_handoff: invalid enter_pc=%s\n",
439	                        tok[1]);
440	                return -1;
441	            }
442	            enter_pc_arg = (uint64_t) v;
443	            pc_mode = 1;
444	        } else if (g_strcmp0(tok[0], "icount") == 0 && tok[1]) {
445	            char *endp = NULL;
446	            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
447	            if (!endp || *endp != '\0' || v == 0) {
448	                fprintf(stderr, "hybrid_handoff: invalid icount=%s\n",
449	                        tok[1]);
450	                return -1;
451	            }
452	            icount_target = (uint64_t) v;
453	            icount_mode = 1;
454	        } else if (g_strcmp0(tok[0], "bbv_out") == 0 && tok[1]) {
455	            bbv_out_path = g_strdup(tok[1]);
456	            bbv_mode = 1;
457	        } else if (g_strcmp0(tok[0], "slice") == 0 && tok[1]) {
458	            char *endp = NULL;
459	            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
460	            if (!endp || *endp != '\0' || v == 0) {
461	                fprintf(stderr, "hybrid_handoff: invalid slice=%s\n",
462	                        tok[1]);
463	                return -1;
464	            }
465	            bbv_slice_target = (uint64_t) v;
466	        } else if (g_strcmp0(tok[0], "slice_at") == 0 && tok[1]) {
467	            char *endp = NULL;
468	            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
469	            if (!endp || *endp != '\0') {
470	                fprintf(stderr, "hybrid_handoff: invalid slice_at=%s\n",
471	                        tok[1]);
472	                return -1;
473	            }
